- CSV (Comma Separated Values) is a plain text format for storing tabular data.
- Each line in the file represents a row, and columns are separated by commas.
- In C++, you can use `ifstream` and a simple loop to manually parse each character.

---

**Example:** Reading and Printing CSV Data Using a `for` Loop

```cpp
#include 
#include 
#include 

using namespace std;

int main() {
    ifstream file("data.csv");  // Open the CSV file

    if (file.is_open()) {
        string line;

        // Read each line from the file
        while (getline(file, line)) {
            string cell = "";

            // Use a traditional for loop to go through each character
            for (int i = 0; i < line.length(); i++) {
                if (line[i] == ',') {
                    cout << cell << " ";  // Print the current cell
                    cell = "";  // Clear for the next cell
                } else {
                    cell += line[i];  // Add character to the current cell
                }
            }

            cout << cell << endl;  // Print the last cell in the row
        }

        file.close();  // Close the file
    } else {
        cout << "Could not open the file!" << endl;
    }

    return 0;
}

